"""
Mock实现模块
本模块提供架构方案中所有接口的Mock实现，用于开发和测试
支持Mock/真实实现一键切换，可配置固定返回、异常抛出等行为
"""

from typing import List, Dict, Any, Optional
from datetime import datetime
import random
import os
import json
from uuid import uuid4
from decimal import Decimal


class MockManager:
    """
    Mock管理器：统一管理Mock切换
    支持通过配置文件或环境变量一键切换Mock/真实实现
    """

    MOCK_CONFIG_PATH = os.path.join(
        os.path.dirname(os.path.abspath(__file__)),
        "..", "..", "config", "mock_config.json"
    )

    @classmethod
    def _load_config(cls) -> Dict[str, Any]:
        """加载Mock配置文件"""
        if os.path.exists(cls.MOCK_CONFIG_PATH):
            try:
                with open(cls.MOCK_CONFIG_PATH, "r", encoding="utf-8") as f:
                    return json.load(f)
            except Exception:
                pass
        return {}

    @classmethod
    def is_mock_enabled(cls, module_name: str) -> bool:
        """
        判断指定模块是否启用Mock

        :param module_name: 模块名称
        :return: 是否启用Mock
        """
        config = cls._load_config()
        module_config = config.get(module_name, {})
        return module_config.get("enabled", True)

    @classmethod
    def set_mock_mode(cls, module_name: str, enabled: bool):
        """
        设置模块的Mock模式

        :param module_name: 模块名称
        :param enabled: 是否启用Mock
        """
        config = cls._load_config()
        if module_name not in config:
            config[module_name] = {}
        config[module_name]["enabled"] = enabled
        os.makedirs(os.path.dirname(cls.MOCK_CONFIG_PATH), exist_ok=True)
        with open(cls.MOCK_CONFIG_PATH, "w", encoding="utf-8") as f:
            json.dump(config, f, ensure_ascii=False, indent=2)

    @classmethod
    def get_mock_config(cls, module_name: str) -> Dict[str, Any]:
        """
        获取模块的Mock配置

        :param module_name: 模块名称
        :return: Mock配置字典
        """
        config = cls._load_config()
        return config.get(module_name, {})


class MockCommandService:
    """命令调度服务Mock实现"""

    MODULE_NAME = "command_service"

    def __init__(self, config: Optional[Dict[str, Any]] = None):
        """
        初始化Mock模块

        :param config: 配置字典，可配置Mock行为
        """
        self.config = config or {}
        self._mock_config = MockManager.get_mock_config(self.MODULE_NAME)

    def dispatch_command(self, command: Dict[str, Any], jwt_token: str) -> Dict[str, Any]:
        """
        统一命令入口Mock实现

        :param command: 命令对象
        :param jwt_token: 用户鉴权Token
        :return: 命令受理回执
        """
        if self._mock_config.get("raise_error", False):
            raise ValueError(f"Mock命令执行错误: {random.choice(['权限不足', '命令参数非法', '乐观锁冲突'])}")

        fixed_value = self._mock_config.get("fixed_value")
        if fixed_value is not None:
            return fixed_value

        return {
            "receipt_id": str(uuid4()),
            "status": "SUCCESS",
            "message": "命令已受理并执行成功",
            "event_id": str(uuid4()),
            "new_version": random.randint(1, 1000),
            "created_at": datetime.now().isoformat()
        }


class MockModelStreamService:
    """模型增量推送服务Mock实现"""

    MODULE_NAME = "model_stream_service"

    def __init__(self, config: Optional[Dict[str, Any]] = None):
        """
        初始化Mock模块

        :param config: 配置字典，可配置Mock行为
        """
        self.config = config or {}
        self._mock_config = MockManager.get_mock_config(self.MODULE_NAME)

    def stream_model_updates(self, model_id: str, client_version: int) -> List[Dict[str, Any]]:
        """
        增量状态推送Mock实现

        :param model_id: 财务模型ID
        :param client_version: 客户端当前版本号
        :return: 增量状态补丁列表
        """
        if self._mock_config.get("raise_error", False):
            raise RuntimeError("Mock长连接异常断开")

        fixed_value = self._mock_config.get("fixed_value")
        if fixed_value is not None:
            return fixed_value

        patch_count = random.randint(1, 5)
        patches = []
        for i in range(patch_count):
            version = client_version + i + 1
            patches.append({
                "patch_id": str(uuid4()),
                "version": version,
                "event_type": random.choice(["LINE_ITEM_UPDATED", "BATCH_CALCULATED", "MODEL_METADATA_UPDATED"]),
                "patch_content": {
                    "updated_items": [
                        {
                            "item_id": f"item_{random.randint(1000, 9999)}",
                            "field": "amount",
                            "value": str(Decimal(random.randint(100, 100000)) / Decimal(100))
                        }
                    ]
                },
                "timestamp": datetime.now().isoformat(),
                "operator": {
                    "role": random.choice(["FINANCE_ADMIN", "FINANCE_EDITOR", "AI_ASSISTANT"]),
                    "user_id": f"user_{random.randint(100, 999)}"
                }
            })
        return patches


