    def __init__(self, config: Optional[Dict[str, Any]] = None):
        """
        初始化Mock模块

        :param config: 配置字典，可配置Mock行为
        """
        self.config = config or {}
        self._mock_config = MockManager.get_mock_config(self.MODULE_NAME)

    def generate_suggestions(self, func_type: str, user_prompt: str, model_context: Dict[str, Any]) -> Dict[str, Any]:
        """
        AI建议生成Mock实现

        :param func_type: 功能类型 补全/改模/校验
        :param user_prompt: 用户输入提示词
        :param model_context: 财务模型上下文
        :return: AI建议结果
        """
        if self._mock_config.get("raise_error", False):
            raise RuntimeError("Mock大模型服务调用超时")

        fixed_value = self._mock_config.get("fixed_value")
        if fixed_value is not None:
            return fixed_value

        event_count = random.randint(1, 3)
        suggest_events = []
        for _ in range(event_count):
            base_event = {
                "eventId": str(uuid4()),
                "aggregateId": model_context.get("model_id", "mock_model_001"),
                "version": random.randint(1, 1000),
                "timestamp": datetime.now().isoformat(),
                "operator": {"role": "AI_ASSISTANT", "user_id": "ai_001"},
                "eventType": "LINE_ITEM_UPDATED"
            }
            suggest_events.append({
                "baseEvent": base_event,
                "itemId": f"item_{random.randint(1000, 9999)}",
                "previousValue": str(Decimal(random.randint(100, 100000)) / Decimal(100)),
                "newValue": str(Decimal(random.randint(100, 100000)) / Decimal(100)),
                "source": "AI_SUGGESTION"
            })

        return {
            "suggest_events": suggest_events,
            "confidence": round(random.uniform(0.7, 0.99), 2),
            "compliance_flag": random.choices([True, False], weights=[0.9, 0.1])[0],
            "suggestion_desc": "根据您的输入自动调整了相关行项数值，符合财务规则要求"
        }


class MockFinancialModelRepository:
    """财务模型存储端口Mock实现"""

    MODULE_NAME = "financial_repository"

    def __init__(self, config: Optional[Dict[str, Any]] = None):
        """
        初始化Mock模块

        :param config: 配置字典，可配置Mock行为
        """
        self.config = config or {}
        self._mock_config = MockManager.get_mock_config(self.MODULE_NAME)
        self._mock_snapshot_store = {}

    def get_snapshot(self, model_id: str) -> Dict[str, Any]:
        """
        获取模型快照Mock实现

        :param model_id: 财务模型ID
        :return: 模型最新快照
        """
        if self._mock_config.get("raise_error", False):
            raise RuntimeError(f"Mock查询异常: 模型{model_id}快照不存在")

        fixed_value = self._mock_config.get("fixed_value")
        if fixed_value is not None:
            return fixed_value

        if model_id in self._mock_snapshot_store:
            return self._mock_snapshot_store[model_id]

        line_items = []
        for i in range(random.randint(10, 50)):
            line_items.append({
                "item_id": f"item_{1000 + i}",
                "item_name": f"行项_{i}",
                "amount": str(Decimal(random.randint(100, 100000)) / Decimal(100)),
                "parent_id": None if i < 5 else f"item_{1000 + random.randint(0, i-1)}"
            })

        snapshot = {
            "modelId": model_id,
            "version": random.randint(1, 1000),
            "lineItems": line_items,
            "snapshotTime": datetime.now().isoformat()
        }
        self._mock_snapshot_store[model_id] = snapshot
        return snapshot

    def get_events(self, model_id: str, start_version: Optional[int] = None) -> List[Dict[str, Any]]:
        """
        获取模型事件列表Mock实现

        :param model_id: 财务模型ID
        :param start_version: 起始版本号
        :return: 事件列表
        """
        if self._mock_config.get("raise_error", False):
            raise RuntimeError(f"Mock查询异常: 模型{model_id}事件不存在")

        fixed_value = self._mock_config.get("fixed_value")
        if fixed_value is not None:
            return fixed_value

        event_count = random.randint(5, 20)
        events = []
        start = start_version or 1
        for v in range(start, start + event_count):
            events.append({
                "eventId": str(uuid4()),
                "aggregateId": model_id,
                "version": v,
                "timestamp": datetime.now().isoformat(),
                "operator": {"role": "FINANCE_ADMIN", "user_id": "user_001"},
                "eventType": random.choice(["LINE_ITEM_UPDATED", "BATCH_CALCULATED"])
            })
        return events


